// Some portions generated by Claude Code
package org.eclipse.rdf4j.query.algebra.evaluation.iterator;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.NoSuchElementException;
import java.util.Random;
import java.util.function.Function;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.common.iteration.CloseableIteration;
import org.eclipse.rdf4j.common.iteration.CloseableIteratorIteration;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.algebra.evaluation.ArrayBindingSet;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.ArrayBindingBasedQueryEvaluationContext;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.QueryEvaluationContext;
import org.junit.jupiter.api.Test;

/**
 * Verifies that the advisory seek hints issued by {@link InnerMergeJoinIterator} never change the join result,
 * regardless of whether the hints are honored fully, partially, or not at all.
 */
public class InnerMergeJoinIteratorSeekTest {

	private final ArrayBindingBasedQueryEvaluationContext context = new ArrayBindingBasedQueryEvaluationContext(
			new QueryEvaluationContext.Minimal(null), new String[] { "a", "b", "c" }, null);
	private final Function<BindingSet, Value> valueFunction = context.getValue("a");
	private final Comparator<Value> cmp = Comparator.comparing(Value::stringValue);

	/**
	 * Seek-capable iteration over binding sets sorted on the join variable. {@code honorEvery} controls how many seek
	 * calls are honored: 1 honors all, 2 every other, 0 none (pure no-op). All calls are recorded either way.
	 */
	private final class SeekCapableIteration implements CloseableIteration<BindingSet> {

		private final List<BindingSet> elements;
		private final List<Value> seekTargets = new ArrayList<>();
		private final int honorEvery;
		private int seekCalls;
		private int index;

		private SeekCapableIteration(List<BindingSet> elements, int honorEvery) {
			this.elements = elements;
			this.honorEvery = honorEvery;
		}

		@Override
		public boolean hasNext() {
			return index < elements.size();
		}

		@Override
		public BindingSet next() {
			if (!hasNext()) {
				throw new NoSuchElementException();
			}
			return elements.get(index++);
		}

		@Override
		public void seek(Value minValue, boolean minInclusive, Value maxValue, boolean maxInclusive) {
			if (minValue == null) {
				return;
			}
			seekTargets.add(minValue);
			seekCalls++;
			if (honorEvery == 0 || seekCalls % honorEvery != 0) {
				return;
			}
			while (index < elements.size()) {
				int compare = cmp.compare(valueFunction.apply(elements.get(index)), minValue);
				if (compare < 0 || (compare == 0 && !minInclusive)) {
					index++;
				} else {
					break;
				}
			}
		}

		@Override
		public boolean supportsSeek() {
			return true;
		}

		@Override
		public void close() {
		}
	}

	@Test
	public void rightLeapfrogResultsIdenticalAndTargetsNonDecreasing() {
		List<BindingSet> left = List.of(left("a005", "b1"), left("a500", "b2"));
		List<BindingSet> right = denseRight(1000);

		SeekCapableIteration seekingRight = new SeekCapableIteration(right, 1);
		List<String> withSeek = join(new SeekCapableIteration(left, 1), seekingRight);
		List<String> plain = join(plain(left), plain(right));

		assertEquals(plain, withSeek);
		assertFalse(seekingRight.seekTargets.isEmpty());
		assertNonDecreasing(seekingRight.seekTargets);
	}

	@Test
	public void leftLeapfrogResultsIdenticalAndTargetsNonDecreasing() {
		List<BindingSet> left = denseLeft(1000);
		List<BindingSet> right = List.of(right("a005", "c1"), right("a500", "c2"));

		SeekCapableIteration seekingLeft = new SeekCapableIteration(left, 1);
		List<String> withSeek = join(seekingLeft, new SeekCapableIteration(right, 1));
		List<String> plain = join(plain(left), plain(right));

		assertEquals(plain, withSeek);
		assertFalse(seekingLeft.seekTargets.isEmpty());
		assertNonDecreasing(seekingLeft.seekTargets);
	}

	@Test
	public void duplicateLeftKeysReplayUnaffected() {
		List<BindingSet> left = List.of(left("a1", "b1"), left("a5", "b51"), left("a5", "b52"), left("a5", "b53"),
				left("a7", "b7"));
		List<BindingSet> right = List.of(right("a1", "c1"), right("a2", "c2"), right("a3", "c3"), right("a5", "c51"),
				right("a5", "c52"), right("a6", "c6"), right("a7", "c7"));

		List<String> withSeek = join(new SeekCapableIteration(left, 1), new SeekCapableIteration(right, 1));
		List<String> plain = join(plain(left), plain(right));

		assertEquals(plain, withSeek);
	}

	@Test
	public void duplicateRightRunsUnaffected() {
		List<BindingSet> left = List.of(left("a1", "b1"), left("a4", "b4"), left("a8", "b8"));
		List<BindingSet> right = List.of(right("a1", "c11"), right("a1", "c12"), right("a2", "c2"), right("a4", "c41"),
				right("a4", "c42"), right("a4", "c43"), right("a5", "c5"), right("a8", "c8"));

		List<String> withSeek = join(new SeekCapableIteration(left, 1), new SeekCapableIteration(right, 1));
		List<String> plain = join(plain(left), plain(right));

		assertEquals(plain, withSeek);
	}

	@Test
	public void noopAndPartialSeekIdentical() {
		List<BindingSet> left = List.of(left("a01", "b1"), left("a10", "b2"), left("a20", "b3"));
		List<BindingSet> right = denseRight(30);

		List<String> plain = join(plain(left), plain(right));
		List<String> noop = join(new SeekCapableIteration(left, 0), new SeekCapableIteration(right, 0));
		List<String> partial = join(new SeekCapableIteration(left, 2), new SeekCapableIteration(right, 2));

		assertEquals(plain, noop);
		assertEquals(plain, partial);
	}

	@Test
	public void randomizedEquivalence() {
		Random random = new Random(42);
		for (int round = 0; round < 100; round++) {
			List<BindingSet> left = randomSide(random, true);
			List<BindingSet> right = randomSide(random, false);

			List<String> plain = join(plain(left), plain(right));
			for (int honorEvery : new int[] { 0, 1, 2, 3 }) {
				List<String> withSeek = join(new SeekCapableIteration(left, honorEvery),
						new SeekCapableIteration(right, honorEvery));
				assertEquals(plain, withSeek, "round " + round + " honorEvery " + honorEvery);
			}
		}
	}

	private List<BindingSet> randomSide(Random random, boolean isLeft) {
		int size = random.nextInt(40);
		List<BindingSet> side = new ArrayList<>(size);
		for (int i = 0; i < size; i++) {
			String key = String.format("a%02d", random.nextInt(20));
			String value = (isLeft ? "b" : "c") + i;
			side.add(isLeft ? left(key, value) : right(key, value));
		}
		side.sort(Comparator.comparing(bindingSet -> bindingSet.getValue("a").stringValue()));
		return side;
	}

	private void assertNonDecreasing(List<Value> targets) {
		for (int i = 1; i < targets.size(); i++) {
			assertTrue(cmp.compare(targets.get(i - 1), targets.get(i)) <= 0,
					"seek targets must be non-decreasing: " + targets.get(i - 1) + " then " + targets.get(i));
		}
	}

	private List<BindingSet> denseRight(int count) {
		List<BindingSet> result = new ArrayList<>(count);
		for (int i = 0; i < count; i++) {
			result.add(right(String.format("a%03d", i), "c" + i));
		}
		return result;
	}

	private List<BindingSet> denseLeft(int count) {
		List<BindingSet> result = new ArrayList<>(count);
		for (int i = 0; i < count; i++) {
			result.add(left(String.format("a%03d", i), "b" + i));
		}
		return result;
	}

	private CloseableIteration<BindingSet> plain(List<BindingSet> elements) {
		return new CloseableIteratorIteration<>(elements.iterator());
	}

	private List<String> join(CloseableIteration<BindingSet> left, CloseableIteration<BindingSet> right) {
		try (InnerMergeJoinIterator iterator = new InnerMergeJoinIterator(left, right, cmp, valueFunction, context)) {
			ArrayList<BindingSet> result = new ArrayList<>();
			while (iterator.hasNext()) {
				result.add(iterator.next());
			}
			return result.stream().map(BindingSet::toString).collect(Collectors.toList());
		}
	}

	private BindingSet left(String key, String value) {
		ArrayBindingSet bindingSet = context.createBindingSet();
		bindingSet.addBinding("a", SimpleValueFactory.getInstance().createLiteral(key));
		bindingSet.addBinding("b", SimpleValueFactory.getInstance().createLiteral(value));
		return bindingSet;
	}

	private BindingSet right(String key, String value) {
		ArrayBindingSet bindingSet = context.createBindingSet();
		bindingSet.addBinding("a", SimpleValueFactory.getInstance().createLiteral(key));
		bindingSet.addBinding("c", SimpleValueFactory.getInstance().createLiteral(value));
		return bindingSet;
	}
}
